import { useState, useEffect } from 'react';
import { api } from '../utils/api';

let _cache = null;
let _cacheTime = 0;
const CACHE_TTL = 5 * 60 * 1000; // 5 min

/**
 * useRegions — fetches all regions from /api/system/regions.
 * Returns { regions: [{ key, label, currency, cached_symbols, enabled, market_hours }], loading }
 * Replaces ALL hardcoded REGIONS arrays across the codebase.
 */
export default function useRegions() {
  const [regions, setRegions] = useState(_cache || []);
  const [loading, setLoading] = useState(!_cache);

  useEffect(() => {
    if (_cache && Date.now() - _cacheTime < CACHE_TTL) {
      setRegions(_cache);
      setLoading(false);
      return;
    }
    let cancelled = false;
    (async () => {
      try {
        const data = await api('/system/regions');
        if (cancelled) return;
        const regionsMap = data?.regions || {};
        const list = Object.entries(regionsMap)
          .filter(([, v]) => v.enabled !== false)
          .map(([key, v]) => ({
            key,
            label: v.label || key,
            currency: v.currency || 'USD',
            cached_symbols: v.cached_symbols || 0,
            enabled: v.enabled !== false,
            market_hours: v.market_hours || {},
          }))
          .sort((a, b) => {
            // US first, crypto last, rest alphabetical
            if (a.key === 'us') return -1;
            if (b.key === 'us') return 1;
            if (a.key === 'crypto') return 1;
            if (b.key === 'crypto') return -1;
            return a.label.localeCompare(b.label);
          });
        _cache = list;
        _cacheTime = Date.now();
        setRegions(list);
      } catch (e) {
        console.warn('useRegions: failed to fetch regions', e);
        // Fallback to basic regions if API fails
        if (!_cache) {
          const fallback = [
            { key: 'us', label: 'US Equities', currency: 'USD', cached_symbols: 0, enabled: true },
            { key: 'crypto', label: 'Crypto', currency: 'USD', cached_symbols: 0, enabled: true },
          ];
          setRegions(fallback);
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => { cancelled = true; };
  }, []);

  return { regions, loading };
}
